#include<iostream>#include<vector>#include<algorithm>#include<cmath>#define ll long longusing namespace std;int main(){    ios_base::sync_with_stdio(false);    cin.tie(NULL);    int t;    cin>>t;    while(t--){        ll n,l,r;        cin>>n>>l>>r;        vector<ll>ans;        bool possible =true;        for(int i=1;i<=n;i++){            int m=((l + i - 1)/i) * i;            if((m)>r){                possible= false;                break;            }            else{                ans.push_back(m);            }        }        if(possible){            cout<<"YES\n";        for(int i=0;i<ans.size();i++){            cout<<ans[i]<<" ";        }        cout<<"\n";    }    else{        cout<<"NO\n";    }    }}